using System;
using System.IO;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests
{
    public static class TestHelpers
    {
        /// <summary>
        /// Creates an in-memory SchoolContext with a unique database name.
        /// </summary>
        public static SchoolContext CreateTestDbContext(string? databaseName = null)
        {
            databaseName ??= Guid.NewGuid().ToString();

            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName)
                .Options;

            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        /// <summary>
        /// Creates a SchoolContext seeded with standard test data and returns it.
        /// </summary>
        public static SchoolContext CreateSeededTestDbContext(string? databaseName = null)
        {
            var context = CreateTestDbContext(databaseName);
            SeedTestData(context);
            return context;
        }

        /// <summary>
        /// Seeds the given context with standard test data:
        /// 3 students, 2 instructors, 2 departments, 3 courses, 2 enrollments, 2 course assignments, 1 office assignment.
        /// </summary>
        public static void SeedTestData(SchoolContext context)
        {
            // Students
            var student1 = new Student
            {
                ID = 1,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };
            var student2 = new Student
            {
                ID = 2,
                LastName = "Alonso",
                FirstMidName = "Meredith",
                EnrollmentDate = new DateTime(2021, 9, 1)
            };
            var student3 = new Student
            {
                ID = 3,
                LastName = "Anand",
                FirstMidName = "Arturo",
                EnrollmentDate = new DateTime(2022, 9, 1)
            };

            // Instructors
            var instructor1 = new Instructor
            {
                ID = 4,
                LastName = "Abercrombie",
                FirstMidName = "Kim",
                HireDate = new DateTime(2015, 3, 11)
            };
            var instructor2 = new Instructor
            {
                ID = 5,
                LastName = "Fakhouri",
                FirstMidName = "Fadi",
                HireDate = new DateTime(2018, 7, 6)
            };

            context.Students.AddRange(student1, student2, student3);
            context.Instructors.AddRange(instructor1, instructor2);
            context.SaveChanges();

            // Departments
            var department1 = new Department
            {
                DepartmentID = 1,
                Name = "English",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = instructor1.ID
            };
            var department2 = new Department
            {
                DepartmentID = 2,
                Name = "Mathematics",
                Budget = 100000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = instructor2.ID
            };

            context.Departments.AddRange(department1, department2);
            context.SaveChanges();

            // Courses
            var course1 = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = department1.DepartmentID
            };
            var course2 = new Course
            {
                CourseID = 4022,
                Title = "Microeconomics",
                Credits = 3,
                DepartmentID = department1.DepartmentID
            };
            var course3 = new Course
            {
                CourseID = 4041,
                Title = "Macroeconomics",
                Credits = 3,
                DepartmentID = department2.DepartmentID
            };

            context.Courses.AddRange(course1, course2, course3);
            context.SaveChanges();

            // Enrollments
            var enrollment1 = new Enrollment
            {
                CourseID = course1.CourseID,
                StudentID = student1.ID,
                Grade = Grade.A
            };
            var enrollment2 = new Enrollment
            {
                CourseID = course2.CourseID,
                StudentID = student2.ID,
                Grade = Grade.B
            };

            context.Enrollments.AddRange(enrollment1, enrollment2);

            // Course Assignments
            var assignment1 = new CourseAssignment
            {
                CourseID = course1.CourseID,
                InstructorID = instructor1.ID
            };
            var assignment2 = new CourseAssignment
            {
                CourseID = course3.CourseID,
                InstructorID = instructor2.ID
            };

            context.CourseAssignments.AddRange(assignment1, assignment2);

            // Office Assignment
            var officeAssignment = new OfficeAssignment
            {
