namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndex()
        {
            var list = new PaginatedList<int>(new List<int> { 1, 2 }, 10, 3, 5);

            Assert.Equal(3, list.PageIndex);
        }

        [Fact]
        public void Constructor_SetsTotalPages_EvenDivision()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);

            Assert.Equal(2, list.TotalPages);
        }

        [Fact]
        public void Constructor_SetsTotalPages_UnevenDivision()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 11, 1, 5);

            Assert.Equal(3, list.TotalPages);
        }

        [Fact]
        public void Constructor_SetsTotalPages_SinglePage()
        {
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 3, 1, 5);

            Assert.Equal(1, list.TotalPages);
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<string> { "a", "b", "c" };

            var list = new PaginatedList<string>(items, 10, 1, 3);

            Assert.Equal(3, list.Count);
            Assert.Contains("a", list);
            Assert.Contains("b", list);
            Assert.Contains("c", list);
        }

        [Fact]
        public void HasPreviousPage_ReturnsFalse_WhenPageIndexIsOne()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);

            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_ReturnsTrue_WhenPageIndexGreaterThanOne()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);

            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_ReturnsTrue_WhenPageIndexLessThanTotalPages()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);

            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_WhenOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);

            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void Create_Page1_ReturnsFirstPageSizeItems()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(5, result.Count);
            Assert.Equal(new List<int> { 1, 2, 3, 4, 5 }, result.ToList());
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
        }

        [Fact]
        public void Create_MiddlePage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(5, result.Count);
            Assert.Equal(new List<int> { 6, 7, 8, 9, 10 }, result.ToList());
            Assert.Equal(2, result.PageIndex);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 5);

            Assert.Equal(2, result.Count);
            Assert.Equal(new List<int> { 11, 12 }, result.ToList());
            Assert.Equal(3, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
        }

        [Fact]
        public void Create_SetsCorrectTotalPages()
        {
            var source = Enumerable.Range(1, 13).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(3, result.TotalPages);
        }
    }
}

